# --- Authentication Middleware ---

class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts authentication info from the request
    and sets current_user in the request state.

    For demonstration, it reads a user ID from the X-User-ID header.
    In production, this would validate a JWT token, session cookie, etc.
    """

    async def dispatch(self, request: Request, call_next):
        # Extract user ID from header (simple auth for demo purposes)
        user_id = request.headers.get("X-User-ID")

        if user_id and user_id in USERS_DB:
            user = USERS_DB[user_id]
            request.state.current_user = {
                "id": user.id,
                "username": user.username,
            }
        else:
            request.state.current_user = None

        response = await call_next(request)
        return response


# --- Context Factory ---

def get_context_value(request, _data):
    """
    Build the GraphQL context from the request.
    Extracts current_user set by the authentication middleware.
    """
    current_user = getattr(request.state, "current_user", None) if hasattr(request, "state") else None
    return {
        "request": request,
        "current_user": current_user,
    }


# --- Schema Creation ---

schema = make_executable_schema(
    type_defs,
    query,
    user_type,
    post_type,
    snake_case_fallback_resolvers,
)


# --- Application Setup ---

app = GraphQL(
    schema,
    context_value=get_context_value,
    debug=True,
)

# Wrap with authentication middleware
from starlette.applications import Starlette
from starlette.routing import Route, Mount

starlette_app = Starlette(
    debug=True,
    middleware=[Middleware(AuthenticationMiddleware)],
    routes=[
        Mount("/graphql", app),
    ],
)


